f _run(): sem = asyncio.Semaphore(concurrency) async with aiohttp.ClientSession() as session: tasks = [_fetch_async(session, asin, api_key, sem) for asin in asin_list] results = await asyncio.gather(*tasks, return_exceptions=True) return [r for r in results if isinstance(r, dict)] return asyncio.run(_run()) What the API returns: { "asin": "B0D6BFMNN5", "buybox_price": 79.99, "buybox_seller_name": "TechMart Direct", "buybox_seller_id": "A1XYZ123ABC", "buybox_is_fba": true, "all_offers": [ {"seller_name": "My Store", "price": 89.99, "is_fba": true}, {"seller_name": "TechMart Direct", "price": 79.99, "is_fba": true} ], "in_stock": true } # analyzer.py from openclaw import Agent, Task from typing import Optional import time class CompetitorPriceAnalyzer: """ Detects competitor price changes and generates AI-powered competitive analysis. Key behaviors: - Only alerts on competitor drops (not your own pricing changes) - Configurable percentage threshold to filter noise - Alert deduplication with cooldown period - Historical change log fed to AI for pattern context """ def __init__(self, threshold_pct: float = 5.0, my_seller_id: str = "", cooldown_minutes: int = 120): self.threshold = threshold_pct self.my_id = my_seller_id self.cooldown = cooldown_minutes * 60 self._baseline = {} # {asin: {"price": float, "log": list}} self._last_alerted = {} # {asin: timestamp} for dedup self.agent = Agent( name="CompetitorAnalyst", role="Amazon Competitive Pricing Analyst", goal="Rapidly assess competitor pricing threats and recommend tactical responses", backstory=( "Senior Amazon marketplace expert with deep knowledge of pricing dynamics, " "seller behavior patterns, and competitive response strategies across multiple categories." ) ) def analyze(self, snapshot: dict) -> Optional[dict]: asin = snapshot["asin"] current_price = snapshot.get("buybox_price") if current_price is None: return None # Initialize baseline on first collection if asin not in self._baseline: self._baseline[asin] = {"price": current_price, "log": []} print(f"[INIT] {asin}: baseline ${current_price}") return None baseline = self._baseline[asin] prev_price = baseline["price"] if prev_price = 10 else "MEDIUM", "asin": asin, "title": snapshot.get("product_title", ""), "competitor_seller": snapshot.get("buybox_seller_name"), "competitor_is_fba": snapshot.get("buybox_is_fba"), "price_from": prev_price, "price_to": current_price, "change_pct": change_pct, "total_offers": len(snapshot.get("all_offers", [])), "ai_analysis": analysis, "detected_at": snapshot["collected_at"] } baseline["price"] = current_price return None # notifier.py import requests import logging import json from datetime import datetime from pathlib import Path logger = logging.getLogger(__name__) class AlertNotifier: def __init__(self, lark_webhook: str = "", slack_webhook: str = "", log_dir: str = "./alert_logs"): self.lark = lark_webhook self.slack = slack_webhook Path(log_dir).mkdir(parents=True, exist_ok=True) self.log_dir = Path(log_dir) def dispatch(self, event: dict): results = {} if self.lark: results["lark"] = self._send_lark(event) if self.slack: results["slack"] = self._send_slack(event) # Persist to local log log_file = self.log_dir / f"alerts_{datetime.utcnow().strftime('%Y%m%d')}.jsonl" with open(log_file, "a") as f: f.write(json.dumps({"event": event, "results": results}) + "
